class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id')
        self.event_type = data.get('event_type')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account')
        self.receiver_account = data.get('receiver_account')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (f"TransactionEvent(id={self.transaction_id}, type={self.event_type}, "
                f"amount={self.amount} {self.currency}, status={self.status})")


class TransactionValidator:
    """Validates transaction events before processing."""

    REQUIRED_FIELDS = ['transaction_id', 'event_type', 'amount', 'sender_account', 'receiver_account']
    VALID_EVENT_TYPES = [
        'payment', 'transfer', 'withdrawal', 'deposit',
        'refund', 'chargeback', 'authorization', 'settlement',
        'fraud_alert', 'account_update'
    ]
    MAX_TRANSACTION_AMOUNT = 1_000_000.00

    @classmethod
    def validate(cls, event: TransactionEvent) -> tuple[bool, list[str]]:
        errors = []

        for field in cls.REQUIRED_FIELDS:
            if getattr(event, field, None) is None:
                errors.append(f"Missing required field: {field}")

        if event.event_type and event.event_type not in cls.VALID_EVENT_TYPES:
            errors.append(f"Invalid event type: {event.event_type}")

        if event.amount is not None:
            try:
                amount = float(event.amount)
                if amount < 0:
                    errors.append(f"Transaction amount cannot be negative: {amount}")
                if amount > cls.MAX_TRANSACTION_AMOUNT:
                    errors.append(f"Transaction amount exceeds maximum: {amount}")
            except (ValueError, TypeError):
                errors.append(f"Invalid amount value: {event.amount}")

        return len(errors) == 0, errors


class FraudDetectionService:
    """Simple rule-based fraud detection."""

    HIGH_AMOUNT_THRESHOLD = 50_000.00
    SUSPICIOUS_CURRENCIES = ['XMR']

    def __init__(self):
        self.transaction_counts: Dict[str, int] = {}
        self.velocity_limit = 10

    def check_transaction(self, event: TransactionEvent) -> dict:
        result = {
            'is_suspicious': False,
            'risk_score': 0.0,
            'flags': []
        }

        amount = float(event.amount)
        if amount > self.HIGH_AMOUNT_THRESHOLD:
            result['risk_score'] += 0.4
            result['flags'].append('high_amount')

        if event.currency in self.SUSPICIOUS_CURRENCIES:
            result['risk_score'] += 0.3
            result['flags'].append('suspicious_currency')

        sender = event.sender_account
        if sender:
            self.transaction_counts[sender] = self.transaction_counts.get(sender, 0) + 1
            if self.transaction_counts[sender] > self.velocity_limit:
                result['risk_score'] += 0.5
                result['flags'].append('velocity_exceeded')

        if result['risk_score'] >= 0.5:
            result['is_suspicious'] = True

        return result


class MessageHandlerRegistry:
    """Registry for dynamic message handlers."""

    def __init__(self):
        self._handlers: Dict[str, list[Callable]] = {}
        self._middleware: list[Callable] = []

    def register_handler(self, event_type: str, handler: Callable):
        if event_type not in self._handlers:
            self._handlers[event_type] = []
        self._handlers[event_type].append(handler)
        logger.info(f"Registered handler '{handler.__name__}' for event type '{event_type}'")

    def register_middleware(self, middleware: Callable):
        self._middleware.append(middleware)
        logger.info(f"Registered middleware '{middleware.__name__}'")

    def get_handlers(self, event_type: str) -> list[Callable]:
        return self._handlers.get(event_type, [])

    def get_middleware(self) -> list[Callable]:
        return self._middleware

    def register_handler_from_config(self, event_type: str, module_path: str, function_name: str):
        """Dynamically load and register a handler from module path."""
        try:
            module = importlib.import_module(module_path)
            handler = getattr(module, function_name)
            if callable(handler):
                self.register_handler(event_type, handler)
            else:
                logger.error(f"{module_path}.{function_name} is not callable")
        except (ImportError, AttributeError) as e:
            logger.error(f"Failed to load handler {module_path}.{function_name}: {e}")


class TransactionProcessor:
    """Core transaction processing engine."""

    def __init__(self, handler_registry: MessageHandlerRegistry):
        self.handler_registry = handler_registry
        self.fraud_service = FraudDetectionService()
        self.processed_count = 0
        self.failed_count = 0
        self.stats: Dict[str, int] = {}

    def process_event(self, event: TransactionEvent) -> Dict[str, Any]:
        result = {
            'transaction_id': event.transaction_id,
            'event_type': event.event_type,
            'processed': False,
            'errors': [],
            'fraud_check': None,
            'handler_results': []
        }

        # Validation
        is_valid, validation_errors = TransactionValidator.validate(event)
        if not is_valid:
            result['errors'] = validation_errors
            self.failed_count += 1
            logger.warning(f"Validation failed for {event.transaction_id}: {validation_errors}")
            return result

        # Fraud detection
        fraud_result = self.fraud_service.check_transaction(event)
        result['fraud_check'] = fraud_result

        if fraud_result['is_suspicious']:
            logger.warning(
                f"Suspicious transaction detected: {event.transaction_id}, "
                f"risk_score={fraud_result['risk_score']}, flags={fraud_result['flags']}"
            )

        # Execute middleware
        for middleware in self.handler_registry.get_middleware():
            try:
                middleware(event)
            except Exception as e:
                logger.error(f"Middleware {middleware.__name__} failed: {e}")

        # Execute handlers
        handlers = self.handler_registry.get_handlers(event.event_type)
        if not handlers:
            logger.warning(f"No handlers registered for event type: {event.event_type}")
            handlers = self.handler_registry.get_handlers('default')

        for handler in handlers:
            try:
                handler_result = handler(event)
                result['handler_results'].append({
                    'handler': handler.__name__,
                    'result': handler_result,
                    'success': True
                })
            except Exception as e:
                logger.error(f"Handler {handler.__name__} failed for {event.transaction_id}: {e}")
                result['handler_results'].append({
                    'handler': handler.__name__,
                    'error': str(e),
                    'success': False
                })
                result['errors'].append(f"Handler {handler.__name__} failed: {str(e)}")

        result['processed'] = len(result['errors']) == 0
        self.processed_count += 1

        # Update stats
        event_type = event.event_type or 'unknown'
        self.stats[event_type] = self.stats.get(event_type, 0) + 1

        return result

    def get_stats(self) -> Dict[str, Any]:
        return {
            'processed_count': self.processed_count,
            'failed_count': self.failed_count,
            'by_event_type': dict(self.stats)
        }


class MessageDeserializer:
    """Handles deserialization of Kafka message values."""

    @staticmethod
    def deserialize_json(value: bytes) -> Optional[Dict[str, Any]]:
        try:
            return json.loads(value.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"JSON deserialization failed: {e}")
            return None

    @staticmethod
    def deserialize_with_schema(value: bytes, schema: Optional[str] = None) -> Optional[Dict[str, Any]]:
        """Extensible deserialization that can support multiple formats."""
        data = MessageDeserializer.deserialize_json(value)
        if data and schema:
            logger.debug(f"Applying schema validation: {schema}")
        return data


