class DeadLetterQueueHandler:
    """Handles messages that fail processing."""

    def __init__(self, dlq_file: str = 'dead_letter_queue.jsonl'):
        self.dlq_file = dlq_file

    def send_to_dlq(self, raw_message: bytes, error: str, topic: str, partition: int, offset: int):
        dlq_entry = {
            'timestamp': datetime.utcnow().isoformat(),
            'topic': topic,
            'partition': partition,
            'offset': offset,
            'error': error,
            'raw_message': raw_message.decode('utf-8', errors='replace') if raw_message else None
        }
        try:
            with open(self.dlq_file, 'a') as f:
                f.write(json.dumps(dlq_entry) + '\n')
            logger.info(f"Message sent to DLQ: topic={topic}, partition={partition}, offset={offset}")
        except IOError as e:
            logger.error(f"Failed to write to DLQ file: {e}")


