class KafkaTransactionConsumer:
    """
    Kafka consumer for processing financial transaction events.

    Consumes messages from configured topics, deserializes them,
    validates, runs fraud checks, and dispatches to registered handlers.
    """

    def __init__(
        self,
        bootstrap_servers: str = 'localhost:9092',
        topics: list[str] = None,
        group_id: str = 'transaction-processor-group',
        auto_offset_reset: str = 'earliest',
        enable_auto_commit: bool = False,
        max_poll_records: int = 100,
        session_timeout_ms: int = 30000,
        heartbeat_interval_ms: int = 10000,
        handler_config: Optional[Dict[str, list]] = None,
        extra_consumer_config: Optional[Dict[str, Any]] = None,
    ):
        self.bootstrap_servers = bootstrap_servers
        self.topics = topics or ['financial-transactions']
        self.group_id = group_id
        self.auto_offset_reset = auto_offset_reset
        self.enable_auto_commit = enable_auto_commit
        self.max_poll_records = max_poll_records
        self.session_timeout_ms = session_timeout_ms
        self.heartbeat_interval_ms = heartbeat_interval_ms
        self.extra_consumer_config = extra_consumer_config or {}

        self._running = False
        self._consumer: Optional[KafkaConsumer] = None

        # Initialize components
        self.deserializer = MessageDeserializer()
        self.handler_registry = MessageHandlerRegistry()
        self.dlq_handler = DeadLetterQueueHandler()

        # Register default handlers
        self._register_default_handlers()

        # Register dynamic handlers from config
        if handler_config:
            self._register_handlers_from_config(handler_config)

        # Initialize processor
        self.processor = TransactionProcessor(self.handler_registry)

    def _register_default_handlers(self):
        """Register built-in transaction handlers."""
        self.handler_registry.register_handler('payment', handle_payment)
        self.handler_registry.register_handler('transfer', handle_transfer)
        self.handler_registry.register_handler('withdrawal', handle_withdrawal)
        self.handler_registry.register_handler('deposit', handle_deposit)
        self.handler_registry.register_handler('refund', handle_refund)
        self.handler_registry.register_handler('chargeback', handle_chargeback)
        self.handler_registry.register_handler('authorization', handle_authorization)
        self.handler_registry.register_handler('settlement', handle_settlement)
        self.handler_registry.register_handler('fraud_alert', handle_fraud_alert)
        self.handler_registry.register_handler('account_update', handle_account_update)
        self.handler_registry.register_handler('default', handle_default)

        # Register middleware
        self.handler_registry.register_middleware(logging_middleware)
        self.handler_registry.register_middleware(timestamp_middleware)

    def _register_handlers_from_config(self, handler_config: Dict[str, list]):
        """
        Register handlers dynamically from configuration.
        
        Config format:
        {
            "event_type": [
                {"module": "my_module", "function": "my_handler"},
                ...
            ]
        }
        """
        for event_type, handlers in handler_config.items():
            for handler_def in handlers:
                module_path = handler_def.get('module')
                function_name = handler_def.get('function')
                if module_path and function_name:
                    self.handler_registry.register_handler_from_config(
                        event_type, module_path, function_name
                    )

    def _create_consumer(self) -> KafkaConsumer:
        """Create and configure Kafka consumer instance."""
        config = {
            'bootstrap_servers': self.bootstrap_servers,
            'group_id': self.group_id,
            'auto_offset_reset': self.auto_offset_reset,
            'enable_auto_commit': self.enable_auto_commit,
            'max_poll_records': self.max_poll_records,
            'session_timeout_ms': self.session_timeout_ms,
            'heartbeat_interval_ms': self.heartbeat_interval_ms,
            'value_deserializer': None,  # We handle deserialization manually
            'key_deserializer': lambda k: k.decode('utf-8') if k else None,
        }
        config.update(self.extra_consumer_config)

        consumer = KafkaConsumer(**config)
        consumer.subscribe(self.topics)
        logger.info(f"Kafka consumer created, subscribed to topics: {self.topics}")
        return consumer

    def _process_message(self, message) -> Optional[Dict[str, Any]]:
        """Process a single Kafka message."""
        topic = message.topic
        partition = message.partition
        offset = message.offset
        raw_value = message.value

        logger.debug(f"Received message: topic={topic}, partition={partition}, offset={offset}")

        # Deserialize
        data = self.deserializer.deserialize_json(raw_value)
        if data is None:
            self.dlq_handler.send_to_dlq(
                raw_value, "Deserialization failed", topic, partition, offset
            )
            return None

        # Create event
        try:
            event = TransactionEvent(data)
        except Exception as e:
            logger.error(f"Failed to create TransactionEvent: {e}")
            self.dlq_handler.send_to_dlq(
                raw_value, f"Event creation failed: {e}", topic, partition, offset
            )
            return None

        # Process
        try:
            result = self.processor.process_event(event)
            if not result['processed']:
                logger.warning(
                    f"Event processing had errors: {event.transaction_id}, errors={result['errors']}"
                )
            else:
                logger.info(f"Successfully processed event: {event.transaction_id}")
            return result
        except Exception as e:
            logger.error(f"Unexpected error processing event {event.transaction_id}: {e}", exc_info=True)
            self.dlq_handler.send_to_dlq(
                raw_value, f"Processing failed: {e}", topic, partition, offset
            )
            return None

    def start(self):
        """Start the consumer loop."""
        self._running = True
        self._consumer = self._create_consumer()

        # Setup graceful shutdown
        signal.signal(signal.SIGINT, self._signal_handler)
        signal.signal(signal.SIGTERM, self._signal_handler)

        logger.info("Transaction consumer started. Waiting for messages...")

        try:
            while self._running:
                try:
                    messages = self._consumer.poll(timeout_ms=1000)

                    for topic_partition, records in messages.items():
                        for record in records:
                            self._process_message(record)

                    # Manual commit after processing batch
                    if messages and not self.enable_auto_commit:
                        try:
                            self._consumer.commit()
                        except KafkaError as e:
                            logger.error(f"Failed to commit offsets: {e}")

                except KafkaError as e:
                    logger.error(f"Kafka error during poll: {e}")

        except Exception as e:
            logger.error(f"Fatal error in consumer loop: {e}", exc_info=True)
        finally:
            self._shutdown()

    def _signal_handler(self, signum, frame):
        """Handle shutdown signals gracefully."""
        logger.info(f"Received signal {signum}, initiating graceful shutdown...")
        self._running = False

    def _shutdown(self):
        """Clean shutdown of the consumer."""
        logger.info("Shutting down consumer...")
        if self._consumer:
            try:
                self._consumer.close()
                logger.info("Kafka consumer closed successfully")
            except Exception as e:
                logger.error(f"Error closing consumer: {e}")

        stats = self.processor.get_stats()
        logger.info(f"Consumer shutdown complete. Final stats: {stats}")

    def stop(self):
        """Stop the consumer."""
        self._running = False


def load_config(config_path: str = None) -> Dict[str, Any]:
    """Load consumer configuration from file or environment."""
    config = {
        'bootstrap_servers': os.environ.get('KAFKA_BOOTSTRAP_SERVERS', 'localhost:9092'),
        'topics': os.environ.get('KAFKA_TOPICS', 'financial-transactions').split(','),
        'group_id': os.environ.get('KAFKA_GROUP_ID', 'transaction-processor-group'),
        'auto_offset_reset': os.environ.get('KAFKA_AUTO_OFFSET_RESET', 'earliest'),
        'enable_auto_commit': os.environ.get('KAFKA_ENABLE_AUTO_COMMIT', 'false').lower() == 'true',
        'max_poll_records': int(os.environ.get('KAFKA_MAX_POLL_RECORDS', '100')),
    }

    if config_path and os.path.exists(config_path):
        try:
            with open(config_path, 'r') as f:
                file_config = json.load(f)
                config.update(file_config)
                logger.info(f"Loaded configuration from {config_path}")
        except (json.JSONDecodeError, IOError) as e:
            logger.warning(f"Failed to load config from {config_path}: {e}")

    return config


def main():
    """Main entry point for the transaction consumer."""
    config_path = sys.argv[1] if len(sys.argv) > 1 else None
    config = load_config(config_path)

    handler_config = config.pop('handler_config', None)

    consumer = KafkaTransactionConsumer(
        bootstrap_servers=config.get('bootstrap_servers', 'localhost:9092'),
        topics=config.get('topics', ['financial-transactions']),
        group_id=config.get('group_id', 'transaction-processor-group'),
        auto_offset_reset=config.get('auto_offset_reset', 'earliest'),
        enable_auto_commit=config.get('enable_auto_commit', False),
        max_poll_records=config.get('max_poll_records', 100),
        handler_config=handler_config,
    )

    consumer.start()


if __name__ == '__main__':
    main()